S1-COL-C:
SELECT SUM(QuotaAmount) total
FROM ForecastingQuota
WHERE {quota_owner_clause}
  AND ForecastingTypeId ='0Db0f000000CwnDCAS'
  AND StartDate >= {fiscal_year_start}
  AND StartDate <= TODAY

