FROM OpportunitySplit
WHERE {owner_clause}
  AND Opportunity.Type = 'Net New'
  AND Split_Type_Name__c = 'Revenue'
  AND Opportunity.CreatedDate >= {time_start}
  AND Opportunity.CreatedDate <= {time_end}

